    model: ImageModelV3;
  }) => PromiseLike<ImageModelV3CallOptions>;

  // Wrap the actual generation call
  wrapGenerate?: (options: {
    doGenerate: () => ReturnType<ImageModelV3['doGenerate']>;
    params: ImageModelV3CallOptions;
    model: ImageModelV3;
  }) => Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>>;
};
```

---

### 10. Provider-Utils Library

**Location:** `/packages/provider-utils/src/`

Key utilities for image providers:

- `postJsonToApi()` - POST JSON request with error handling
- `postFormDataToApi()` - POST form data (for file uploads)
- `getFromApi()` - GET request with response handling
- `createJsonResponseHandler()` - Zod schema validation
- `createBinaryResponseHandler()` - Binary data handling
- `combineHeaders()` - Header merging
- `convertImageModelFileToDataUri()` - File to data URI conversion
- `parseProviderOptions()` - Provider-specific option parsing
- `lazySchema()` / `zodSchema()` - Schema definition helpers
- `delay()` - Utility for polling

---

### 11. Public API Exports

**packages/openai/src/index.ts:**
```typescript
export { createOpenAI, openai } from './openai-provider';
export type { OpenAIProvider, OpenAIProviderSettings };
export type { OpenAILanguageModelChatOptions };
export type { OpenAIEmbeddingModelOptions };
// Note: Image model options are NOT exported by default in OpenAI
```

**packages/black-forest-labs/src/index.ts:**
```typescript
export { createBlackForestLabs, blackForestLabs } from './black-forest-labs-provider';
export type {
  BlackForestLabsProvider,
  BlackForestLabsProviderSettings,
};
export type {
  BlackForestLabsImageModelId,
  BlackForestLabsAspectRatio,
};
export type { BlackForestLabsImageModelOptions };
```

---

### 12. Usage Pattern (From Tests)

```typescript
import { createOpenAI } from '@ai-sdk/openai';

// Create provider with config
const provider = createOpenAI({ apiKey: 'test-api-key' });

// Get image model
const model = provider.image('dall-e-3');
// or
const model = provider.imageModel('dall-e-3');

// Generate images
const result = await model.doGenerate({
  prompt: 'A cute baby sea otter',
  files: undefined,
  mask: undefined,
  n: 1,
  size: '1024x1024',
  aspectRatio: undefined,
  seed: undefined,
  providerOptions: { 
    openai: { 
      style: 'vivid' 
    } 
  },
  headers: {
    'OpenAI-Organization': 'test-org',
  },
});

// result contains:
// {
//   images: ['base64string...'],
//   warnings: [],
//   providerMetadata: { openai: { images: [...] } },
//   response: { timestamp, modelId, headers },
//   usage: { inputTokens, outputTokens, totalTokens }
// }
```

---

### 13. Key Design Patterns

1. **Specification Versioning**: All models declare `specificationVersion: 'v3'` for discriminated unions
2. **Factory Pattern**: Providers expose factory functions (`createOpenAI`, `createBlackForestLabs`)
3. **Configuration Objects**: Config passed to model constructor with headers as callable functions
4. **Provider Options**: Nested object allowing provider-specific customizations without breaking SDK contract
5. **Warning System**: Models return warnings for unsupported features
6. **Flexible Output**: Models return base64 strings OR Uint8Array based on API capabilities
7. **Async Polling**: Some providers (Black Forest Labs, Replicate) handle async jobs with polling
8. **Middleware**: Can wrap models to modify behavior without changing implementation

---

### 14. File Paths Summary

**Core Provider Files:**
- `/packages/provider/src/image-model/v3/image-model-v3.ts` - Main interface
- `/packages/provider/src/image-model/v3/image-model-v3-call-options.ts` - Input contract
- `/packages/provider/src/image-model/v3/image-model-v3-file.ts` - File types
- `/packages/provider/src/image-model/v3/image-model-v3-usage.ts` - Token usage
- `/packages/provider/src/provider/v3/provider-v3.ts` - Provider interface

**OpenAI Implementation:**
- `/packages/openai/src/openai-provider.ts` - Provider factory
- `/packages/openai/src/image/openai-image-model.ts` - Image model class
- `/packages/openai/src/image/openai-image-api.ts` - API response schemas
- `/packages/openai/src/image/openai-image-options.ts` - Model configuration

**Black Forest Labs Example:**
- `/packages/black-forest-labs/src/black-forest-labs-provider.ts` - Provider factory
- `/packages/black-forest-labs/src/black-forest-labs-image-model.ts` - Image model with polling
- `/packages/black-forest-labs/src/black-forest-labs-image-settings.ts` - Model types

**Middleware:**
- `/packages/provider/src/image-model-middleware/v3/image-model-v3-middleware.ts`

This architecture enables clean provider integration while maintaining backward compatibility through versioning and flexible, extensible option passing.

